import { Component } from '@angular/core';

import { SelectTabService } from 'src/app/services/select-tab.service';
import pageData from './pageData';

@Component({
  selector: 'app-list-page',
  templateUrl: './list-page.page.html',
  styleUrls: ['./list-page.page.scss'],
})
export class ListPagePage {

  public tabTitle;
  public subscribe;

  constructor(
    public selectTab:SelectTabService
  ) { }

  ionViewWillEnter() {
    this.subscribe = this.selectTab.selectTab.subscribe({
      next: (v) => {
        const v1:any = v;
        this.tabTitle = pageData[v1].title
      }
    });
  }

  ionViewDidLeave(){
    this.subscribe.unsubscribe();
  }

}
